'use strict';
({ params, imports }) => {
    const individual = params.entity;
    const moment = imports.moment;

    let eligibility = false;

    const dob = individual.dateOfBirth ? moment(individual.dateOfBirth) : null;
    if (!dob || !dob.isValid()) return false;

    const today = moment();
    const fiveYearsAgo = today.clone().subtract(5, 'years');
    const nineteenYearsAgo = today.clone().subtract(19, 'years');
    const fortyNineYearsAgo = today.clone().subtract(49, 'years');

    const gender = individual.gender ? individual.gender.name : null;

    let isEligibleByAge = false;
    if (gender === 'Male') {
        isEligibleByAge = dob.isBetween(nineteenYearsAgo, fiveYearsAgo, null, '[)');
    } else if (gender === 'Female' || gender === 'Other') {
        isEligibleByAge = dob.isBetween(fortyNineYearsAgo, fiveYearsAgo, null, '[)');
    }

    if (!isEligibleByAge) return false;

    const schoolTypeUUID = '79f9fc96-7817-491c-a202-9e98ead1574c';    
    const isPartOfSchool = false;

    if(individual.lowestAddressLevel.type == 'School' || individual.lowestAddressLevel.typeUuid == schoolTypeUUID){
      isPartOfSchool = true;
    }

    if (isPartOfSchool) {
        const encounters = Array.isArray(individual.encounters) ? individual.encounters : [];

        const foundEligibleCancellation = encounters.some(enc =>
            enc &&
            enc.encounterType &&
            enc.encounterType.name === 'School Health - Screening Follow up' &&
            enc.cancelDateTime &&
            Array.isArray(enc.cancelObservations) &&
            enc.cancelObservations.some(obs => {
                if (
                    obs &&
                    obs.concept &&
                    obs.concept.uuid === 'f52e6c46-f982-4331-95c4-26bb36c48e72' &&
                    typeof obs.valueJSON === 'string'
                ) {
                    try {
                        const parsed = JSON.parse(obs.valueJSON);
                        return parsed.answer === '6250a8db-2bfc-4bc2-9f26-ca9e5ac41619';
                    } catch (e) {
                        return false;
                    }
                }
                return false;
            })
        );

        eligibility = foundEligibleCancellation;
    } else {
        eligibility = true;
    }

    return eligibility;
};

'use strict';
({params, imports}) => {
  const individual = params.entity;
  const moment = imports.moment;
  let eligibility = true;

  const condition11 = new imports.rulesConfig.RuleCondition({individual}).when.ageInYears.greaterThanOrEqualTo(12).and.when.ageInYears.lessThanOrEqualTo(50).and.when.gender.equals("Female").matches();

  eligibility = condition11 ;

  return eligibility;
};

'use strict';
({params, imports}) => {
  const individual = params.entity;
  const moment = imports.moment;
  let eligibility = true;

  const twoYearsAgo = moment().subtract(2, 'years').startOf('day');
  const dateOfBirth = moment(individual.dateOfBirth).startOf('day');

  eligibility = dateOfBirth.isSameOrAfter(twoYearsAgo);

  return eligibility;
};

"use strict";
({ params, imports }) => {
  const programEncounter = params.entity;
  const moment = imports.moment;
  const scheduleBuilder = new imports.rulesConfig.VisitScheduleBuilder({programEncounter});

  const encounterType = programEncounter.encounterType.name;

  const isActiveInProgram = !programEncounter.programEnrolment.programExitDateTime;

  let deliveryEncounters = programEncounter.programEnrolment.getEncountersOfType('Delivery');

  const condition11 = new imports.rulesConfig.RuleCondition({programEncounter}).when.valueInCancelEncounter("e19ded48-c845-4a50-91ab-0d559d570b39").containsAnyAnswerConceptName("7aa91832-43d7-4ed6-8fe4-feabf1455cf7","c28401fc-3b61-4c8d-a2a6-6c97df6ff61b").matches();

  if(deliveryEncounters.length == 0 && isActiveInProgram && condition11){
    const earliestDate = moment(programEncounter.cancelDateTime).add(30, 'days').toDate();
    const maxDate = moment(programEncounter.cancelDateTime).add(40, 'days').toDate();
    scheduleBuilder.add({name: "ANC - Follow Up", encounterType: "ANC - Follow Up", earliestDate, maxDate});  
  }

  return scheduleBuilder.getAll();
};

