'use strict';
({params, imports}) => {
  const programEncounter = params.entity;
  const moment = imports.moment;
  const formElement = params.formElement;
  const _ = imports.lodash;
  let visibility = true;
  let value = null;
  let answersToSkip = [];
  let validationErrors = [];


  if (programEncounter.encounterDateTime) {

    const existingValue = programEncounter.getObservationReadableValue(formElement.concept.uuid);
    if (existingValue) {
      value = existingValue;
      return new imports.rulesConfig.FormElementStatus(formElement.uuid, visibility, value, answersToSkip, validationErrors);
    }
  }


  const condition11 = new imports.rulesConfig.RuleCondition({programEncounter, formElement})
    .when.valueInEnrolment("bb3a806d-2b8b-4982-a46c-b82204cac8a1")
    .defined
    .matches();


  const allEncounters = programEncounter.programEnrolment.encounters;


  const previousEncounters = allEncounters
    .filter(enc => 
      enc.encounterType.name === programEncounter.encounterType.name && 
      !enc.voided &&
      enc.uuid !== programEncounter.uuid 
    )
    .sort((enc1, enc2) => moment(enc2.encounterDateTime).diff(moment(enc1.encounterDateTime)));


  if (previousEncounters.length > 0) {

    const latestEncounter = previousEncounters[0];

    const previousValue = latestEncounter.getObservationReadableValue(formElement.concept.uuid);
    if (previousValue) {
      value = previousValue;
    }
  } else if (condition11) {
    value = "No";
  }

  return new imports.rulesConfig.FormElementStatus(formElement.uuid, visibility, value, answersToSkip, validationErrors);
};

