'use strict';
({params, imports}) => {
  const programEncounter = params.entity;
  const moment = imports.moment;
  const formElement = params.formElement;
  const RuleCondition = imports.rulesConfig.RuleCondition;

  let visibility = true;
  let value = null;
  let answersToSkip = [];
  let validationErrors = [];

  const sonographyCount = new RuleCondition({programEncounter, formElement})
    .when.valueInEncounter("bf42cdce-dc5a-485e-b8c8-1fc349153e4a")
    .greaterThan(0)
    .matches();

  visibility = sonographyCount;

  if (visibility) {
    const lastSonographyDateRaw = programEncounter.getObservationValue("Date of last Sonography");
    const lastSonographyDate = moment(lastSonographyDateRaw);

    if (!lastSonographyDate.isValid() || lastSonographyDate.isAfter(moment())) {
      validationErrors.push("Selected Date is not acceptable");
    }
  }

  return new imports.rulesConfig.FormElementStatus(
    formElement.uuid,
    visibility,
    value,
    answersToSkip,
    validationErrors
  );
};

