    visibility = height && weight;

    const nutritionStatus = {
        '3': '>3 SD (Obese)',
        '2': '>2 SD to <3 SD (Overweight)',
        '1': '>1 SD to <2 SD (Normal)',
        '0': '<1 SD to > -1 SD (Normal)',
        '-1': '< -1 SD to > -2 SD (Normal)',
        '-2': '< -2 SD to > -3 SD (Wasted)',
        '-3': '< -3 SD (Severely wasted)'
    };


    function getZScore(zScore) {
        if(zScore >= 3) return '3';
        if(zScore >= 2) return '2';
        if(zScore >= 1) return '1';
        if(zScore >= 0) return '0';
        if(zScore >= -1) return '-1';
        if(zScore >= -2) return '-2';
        return '-3';
    }

    if(visibility) {

        const zScoresForChild = ruleServiceLibraryInterfaceForSharingModules.common.getZScore(individual, asOnDate, weight, height);

        const zScore = getZScore(zScoresForChild.wfh);

        value = nutritionStatus[zScore];
    }

    return new imports.rulesConfig.FormElementStatus(formElement.uuid, visibility, value, answersToSkip, validationErrors);
