({ params, imports }) => {
  const programEncounter = params.entity;
  const formElement = params.formElement;
  const _ = imports.lodash;
  const moment = imports.moment;

  let visibility = false;
  let value = null;
  let answersToSkip = [];
  let validationErrors = [];

  const gender = programEncounter.individual && programEncounter.individual.gender
    ? programEncounter.individual.gender.name
    : null;
  const dob = programEncounter.individual && programEncounter.individual.dateOfBirth
    ? moment(programEncounter.individual.dateOfBirth)
    : null;

  if (!dob || !dob.isValid()) {
    return new imports.rulesConfig.FormElementStatus(formElement.uuid, false, value, answersToSkip, validationErrors);
  }

  const today = moment();
  const fiveYearsAgo = today.clone().subtract(5, 'years');
  const nineteenYearsAgo = today.clone().subtract(19, 'years');
  const fortyNineYearsAgo = today.clone().subtract(49, 'years');

  const ageYears = today.diff(dob, 'years');

  if ((gender === 'Female' || gender === 'Other')) {
    if (dob.isBetween(fortyNineYearsAgo, fiveYearsAgo, null, '[)')) {
      visibility = true;
    }
  }

  if (gender === 'Male') {
    if (dob.isBetween(nineteenYearsAgo, fiveYearsAgo, null, '[)')) {
      visibility = true;
    }
  }
  return new imports.rulesConfig.FormElementStatus(formElement.uuid,visibility,value,answersToSkip,validationErrors);
};

