({ params, imports }) => {
  const programEncounter = params.entity;
  const formElement = params.formElement;
  const _ = imports.lodash;
  const moment = imports.moment;

  let visibility = false;
  let value = null;
  let answersToSkip = [];
  let validationErrors = [];

  const hbValue = programEncounter.getObservationValue('7bc512e6-117c-4140-9209-7dfc231bae81');
  const gender = programEncounter.individual.gender.name;
  const age = programEncounter.individual.getAge()._durationValue; // years

  const classifyHb = (hb, cutoffs) => {
    if (hb < cutoffs.severe) return "Less than 8 gm/dl-Severe Anaemia";
    if (hb < cutoffs.moderate) return "8- 10.9 gm/dl-Moderate Anaemia";
    if (cutoffs.mild === 12) return (hb < cutoffs.mild ? "11-11.9 gm/dl-Mild Anaemia" : "More than 11.9 gm/dl-Normal");
    if (cutoffs.mild === 13) return (hb < cutoffs.mild ? "11-12.9 gm/dl - Mild Anaemia" : "More than 12.9 gm/dl - Normal");
  };

  if (hbValue) {
    visibility = true;

    if ((gender === 'Female' || gender === 'Other') && (age >= 5 && age < 49)) {
      value = classifyHb(hbValue, { severe: 8, moderate: 11, mild: 12 });
    } else if (gender === 'Male') {
      if (age >= 5 && age <= 14) {
        value = classifyHb(hbValue, { severe: 8, moderate: 11, mild: 12 });
      } else if (age >= 15 && age <= 19) {
        value = classifyHb(hbValue, { severe: 8, moderate: 11, mild: 13 });
      }
    }
  }
  return new imports.rulesConfig.FormElementStatus(formElement.uuid,visibility,value,answersToSkip,validationErrors);
};

