({ params, imports }) => {
  const encounter = params.entity;
  const moment = imports.moment;
  const formElement = params.formElement;

  let visibility = false;
  let value = null;
  let answersToSkip = [];
  let validationErrors = [];

  const gender = encounter.individual && encounter.individual.gender
    ? encounter.individual.gender.name
    : null;
  const dob = encounter.individual && encounter.individual.dateOfBirth
    ? moment(encounter.individual.dateOfBirth)
    : null;

  if (!dob || !dob.isValid()) {
    return new imports.rulesConfig.FormElementStatus(formElement.uuid, false, value, answersToSkip, validationErrors);
  }

  const today = moment();
  const fiveYearsAgo = today.clone().subtract(5, 'years');
  const nineteenYearsAgo = today.clone().subtract(19, 'years');
  const fortyNineYearsAgo = today.clone().subtract(49, 'years');

  const ageYears = today.diff(dob, 'years');

  if ((gender === 'Female' || gender === 'Other')) {
    if (dob.isBetween(fortyNineYearsAgo, fiveYearsAgo, null, '[)')) {
      visibility = true;
    }
  }

  if (gender === 'Male') {
    if (dob.isBetween(nineteenYearsAgo, fiveYearsAgo, null, '[)')) {
      visibility = true;
    }
  }

  return new imports.rulesConfig.FormElementStatus(formElement.uuid, visibility, value, answersToSkip, validationErrors);
};

'use strict';
({params, imports}) => {
  const encounter = params.entity;
  const formElement = params.formElement;
  let visibility = false;
  let value = null;
  let answersToSkip = [];
  let validationErrors = [];

  const hbValue = encounter.getObservationValue('7bc512e6-117c-4140-9209-7dfc231bae81');
  const gender = encounter.individual.gender.name;
  const age = encounter.individual.getAge()._durationValue; // years

  const classifyHb = (hb, cutoffs) => {
    if (hb < cutoffs.severe) return "Less than 8 gm/dl-Severe Anaemia";
    if (hb < cutoffs.moderate) return "8- 10.9 gm/dl-Moderate Anaemia";

    if (cutoffs.mild === 12) {
      return hb < 12
        ? "11-11.9 gm/dl-Mild Anaemia"
        : "More than 11.9 gm/dl-Normal";
    }

    if (cutoffs.mild === 13) {
      return hb < 13
        ? "11-12.9 gm/dl - Mild Anaemia"
        : "More than 12.9 gm/dl - Normal";
    }

    return null;
  };

  if (hbValue) {
    visibility = true;

    if ((gender === 'Female' || gender === 'Other') && (age >= 5 && age < 49)) {
      value = classifyHb(hbValue, { severe: 8, moderate: 11, mild: 12 });
    } else if (gender === 'Male') {
      if (age >= 5 && age <= 14) {
        value = classifyHb(hbValue, { severe: 8, moderate: 11, mild: 12 });
      } else if (age >= 15 && age <= 19) {
        value = classifyHb(hbValue, { severe: 8, moderate: 11, mild: 13 });
      }
    }
  }

  return new imports.rulesConfig.FormElementStatus(
    formElement.uuid,
    visibility,
    value,
    answersToSkip,
    validationErrors
  );
};

