"use strict";
({ params, imports }) => {
  const encounter = params.entity;
  const moment = imports.moment;
  const scheduleBuilder = new imports.rulesConfig.VisitScheduleBuilder({ encounter });

  const encounterType = encounter.encounterType.name;

  console.log('encounter-->',encounter);

  const baseDate = encounter.cancelDateTime;
  console.log("baseDate -->", baseDate);

  function isAlreadyScheduled(nextVisitName, earliestDate) {
    const nextVisitDate = moment(earliestDate).startOf("day");
    const existingEncounters = encounter.individual?.encounters || [];

    console.log(`Checking for ${nextVisitName} on ${nextVisitDate.format("YYYY-MM-DD")}`);

    existingEncounters.forEach((enc) => {
      const name = enc.name?.trim();
      const date = enc.earliestVisitDateTime
        ? moment(enc.earliestVisitDateTime).format("YYYY-MM-DD")
        : "N/A";
      console.log(`  Encounter: ${name}, Date: ${date}, Voided: ${enc.voided}`);
    });

    return existingEncounters.some((enc) => {
      const encounterName = enc.name?.trim();
      const scheduledDate = enc.earliestVisitDateTime
        ? moment(enc.earliestVisitDateTime).startOf("day")
        : null;

      return (
        enc.voided === false &&
        (
          encounterName === nextVisitName ||
          (scheduledDate && scheduledDate.isSame(nextVisitDate, "day"))
        )
      );
    });
  }

  function getNextVisitName(currentVisitName) {
    const match = currentVisitName?.match(/^School Health - Screening Follow up (\d+)$/);
    if (match) {
      const nextNumber = parseInt(match[1], 10) + 1;
      return `School Health - Screening Follow up ${nextNumber}`;
    }
    return "School Health - Screening Follow up 2";
  }

  const dob = encounter.individual?.dateOfBirth;
  const today = moment();
  const ageInYears = moment(today).diff(moment(dob), "years", true);
  const isAgeEligible = ageInYears >= 5 && ageInYears <= 19;

  console.log("isAgeEligible--->", isAgeEligible);

  const nextVisitName = getNextVisitName(encounter.name);
  console.log("Next Visit Name -->", nextVisitName);

  const condition11 = new imports.rulesConfig.RuleCondition({ encounter })
    .when
    .valueInCancelEncounter("f52e6c46-f982-4331-95c4-26bb36c48e72")
    .containsAnyAnswerConceptName(
      "7aa91832-43d7-4ed6-8fe4-feabf1455cf7",
      "c28401fc-3b61-4c8d-a2a6-6c97df6ff61b"
    )
    .matches();

  console.log("condition11 -->", condition11);

  if (condition11 && isAgeEligible) {
    const earliestDate = moment(baseDate).add(3, "month").toDate();
    const maxDate = moment(earliestDate).add(10, "days").toDate();

    console.log("earliestDate -->", earliestDate);
    console.log("maxDate -->", maxDate);

    if (!isAlreadyScheduled(nextVisitName, earliestDate)) {
      console.log("Adding visit to schedule...");
      scheduleBuilder.add({
        name: nextVisitName,
        encounterType: encounterType,
        earliestDate,
        maxDate
      });
    } else {
      console.log("Already scheduled. Skipping...");
    }
  }

  return scheduleBuilder.getAll();
};

