programEligibility.jsRule:
'use strict';
({ params, imports }) => {
    const individual = params.entity;
    const moment = imports.moment;

    let eligibility = false;

    const dob = individual.dateOfBirth ? moment(individual.dateOfBirth) : null;
    if (!dob || !dob.isValid()) return false;

    const today = moment();
    const fiveYearsAgo = today.clone().subtract(5, 'years');
    const nineteenYearsAgo = today.clone().subtract(19, 'years');
    const fortyNineYearsAgo = today.clone().subtract(49, 'years');

    const gender = individual.gender ? individual.gender.name : null;

    let isEligibleByAge = false;
    if (gender === 'Male') {
        isEligibleByAge = dob.isBetween(nineteenYearsAgo, fiveYearsAgo, null, '[)');
    } else if (gender === 'Female' || gender === 'Other') {
        isEligibleByAge = dob.isBetween(fortyNineYearsAgo, fiveYearsAgo, null, '[)');
    }

    if (!isEligibleByAge) return false;

    const schoolTypeUUID = '79f9fc96-7817-491c-a202-9e98ead1574c';    
    const isPartOfSchool = false;

    if(individual.lowestAddressLevel.type == 'School' || individual.lowestAddressLevel.typeUuid == schoolTypeUUID){
      isPartOfSchool = true;
    }

    if (isPartOfSchool) {
        const encounters = Array.isArray(individual.encounters) ? individual.encounters : [];

        const foundEligibleCancellation = encounters.some(enc =>
            enc &&
            enc.encounterType &&
            enc.encounterType.name === 'School Health - Screening Follow up' &&
            enc.cancelDateTime &&
            Array.isArray(enc.cancelObservations) &&
            enc.cancelObservations.some(obs => {
                if (
                    obs &&
                    obs.concept &&
                    obs.concept.uuid === 'f52e6c46-f982-4331-95c4-26bb36c48e72' &&
                    typeof obs.valueJSON === 'string'
                ) {
                    try {
                        const parsed = JSON.parse(obs.valueJSON);
                        return parsed.answer === '6250a8db-2bfc-4bc2-9f26-ca9e5ac41619';
                    } catch (e) {
                        return false;
                    }
                }
                return false;
            })
        );

        eligibility = foundEligibleCancellation;
    } else {
        eligibility = true;
    }

    return eligibility;
};

