'use strict';
({params, imports}) => {
    const encounter = params.entity;
    const moment = imports.moment;
    const formElement = params.formElement;
    const _ = imports.lodash;
    let visibility = true;
    let value = null;
    let answersToSkip = [];
    let answersToShow = [];
    let validationErrors = [];
    let gender = encounter.individual.gender;
    let age = encounter.individual.getAgeInYears(asOnDate = moment(), precise = true)

    visibility = gender.isFemale() || (gender.isMale() && age >= 10)

    function getAnswerToShow(HbValues) {
        let answerList = [];
        _.forEach(HbValues, (answer) => {
            const answerToShow = formElement.getAnswerWithConceptUuid(answer);
            if (answerToShow) answerList.push(answerToShow);
        });
        return answerList;
    }

    if(visibility) {
        femaleHbValues = ['f015ffb9-babc-434f-87d1-d46c1a52fa2d', '5b943e5b-56c7-40b4-977d-9c9291fec8b0', '9847a475-3347-49d0-9f67-60a985003f96', '559f614a-1386-4662-ba25-f2cd5017ea50']
        maleHbValuesAge10to15 = ['f015ffb9-babc-434f-87d1-d46c1a52fa2d', 'f2ce9989-d20c-4fe9-895b-c00ab9b5690e', '2cc1be43-1a35-4cb6-9120-5c114c9e58c2', '559f614a-1386-4662-ba25-f2cd5017ea50']
        maleHbValuesAgeMoreThan15 = ['f015ffb9-babc-434f-87d1-d46c1a52fa2d', 'f2ce9989-d20c-4fe9-895b-c00ab9b5690e', '18a31a40-5e6d-496c-93e7-d8a47fa45876', 'be8e6b63-d5e8-47af-9efe-2cdfbd84c3ba']

        if(gender.isFemale()) {
            answersToShow = getAnswerToShow(femaleHbValues)
        } else if(gender.isMale() && age > 15) {
            answersToShow = getAnswerToShow(maleHbValuesAgeMoreThan15)
        } else if(gender.isMale() && age >= 10) {
            answersToShow = getAnswerToShow(maleHbValuesAge10to15)
        } else {
            visibility = false;
        }
    }

    return new imports.rulesConfig.FormElementStatus(formElement.uuid, visibility, value, answersToSkip, validationErrors, answersToShow);
};

'use strict';
({params, imports}) => {
    const encounter = params.entity;
    const moment = imports.moment;
    const formElement = params.formElement;
    const _ = imports.lodash;
    let visibility = true;
    let value = null;
    let answersToSkip = [];
    let validationErrors = [];
    const encounters = encounter.individual.getEncounters();

    if(encounters && encounters.length > 0) {
        const hbScreeingEncounter = encounter.filter((enc) => enc.encounterType.name == '' && enc.encounterDateTime != null)
        if(hbScreeingEncounter && hbScreeingEncounter.length > 0) {
            const noOfIfaTablets = hbScreeingEncounter.getObservationReadableValue('No. of IFA Tablets given in current visit');
            if(noOfIfaTablets) {
                value = noOfIfaTablets;
            }
        }
    }

    if(value == null) visibility = false;

    return new imports.rulesConfig.FormElementStatus(formElement.uuid, visibility, value, answersToSkip, validationErrors);
};

