'use strict';
({ params, imports }) => {
  const individual = params.entity;
  const formElement = params.formElement;

  let visibility = true;
  let value = null;
  let answersToSkip = [];
  let validationErrors = [];

  const RuleCondition = imports.rulesConfig.RuleCondition;

  /* ---------------- SAFE HELPERS ---------------- */

  function getParentLocation(location) {
    if (
      location &&
      location.locationMappings &&
      location.locationMappings.length > 0 &&
      location.locationMappings[0] &&
      location.locationMappings[0].parent
    ) {
      return location.locationMappings[0].parent;
    }
    return null;
  }

  /* ---------------- CHECK ADDRESS ---------------- */

  const hasIndividualAddress = new RuleCondition({
    individual: individual,
    formElement: formElement
  }).when.lowestAddressLevel.defined.matches();

  if (!hasIndividualAddress) {
    return new imports.rulesConfig.FormElementStatus(
      formElement.uuid,
      visibility,
      value,
      answersToSkip,
      validationErrors
    );
  }

  /* ---------------- INDIVIDUAL DATA ---------------- */

  const individualLowestAddress = individual.lowestAddressLevel.uuid;
  const individualLowestAddressName = individual.lowestAddressLevel.name;
  const individualLowestAddressType = individual.lowestAddressLevel.typeUuid;

  const individualParent = getParentLocation(individual.lowestAddressLevel);
  const individualSecondLowestAddress =
    individualParent ? individualParent.uuid : null;

  /* ---------------- CONSTANTS ---------------- */

  const FALIYA_UUID = '4c23ae7d-6f0c-4924-93f2-7296bfe96fef';
  const SCHOOL_UUID = '79f9fc96-7817-491c-a202-9e98ead1574c';

  /* ---------------- GROUP CONTEXT (SAFE) ---------------- */

  const groupSubject =
    params.entityContext && params.entityContext.group
      ? params.entityContext.group
      : null;

  /* -------- CASE 1: GROUP CONTEXT -------- */

  if (groupSubject && groupSubject.lowestAddressLevel) {
    const householdLowestAddress = groupSubject.lowestAddressLevel.uuid;

    const householdParent = getParentLocation(groupSubject.lowestAddressLevel);
    const householdSecondLowestAddress =
      householdParent ? householdParent.uuid : null;

    if (
      individualLowestAddressType === FALIYA_UUID &&
      householdLowestAddress &&
      individualLowestAddress !== householdLowestAddress
    ) {
      validationErrors.push(
        'Address selected for individual is not same as Household address.'
      );
    }

    if (
      individualLowestAddressType === SCHOOL_UUID &&
      householdSecondLowestAddress &&
      individualSecondLowestAddress &&
      individualSecondLowestAddress !== householdSecondLowestAddress
    ) {
      validationErrors.push(
        'Selected village for individual is not same as Household village.'
      );
    }
  }

  /* -------- CASE 2: FALLBACK VIA INDIVIDUAL GROUPS -------- */

  else if (
    individual.groups &&
    individual.groups.length > 0 &&
    individual.groups[0].memberSubject &&
    individual.groups[0].memberSubject.lowestAddressLevel
  ) {
    const householdSubject = individual.groups[0].memberSubject;

    const householdLowestAddress =
      householdSubject.lowestAddressLevel.uuid;

    const householdParent = getParentLocation(
      householdSubject.lowestAddressLevel
    );
    const householdSecondLowestAddress =
      householdParent ? householdParent.uuid : null;

    if (
      individualLowestAddressType === FALIYA_UUID &&
      householdLowestAddress &&
      individualLowestAddress !== householdLowestAddress
    ) {
      validationErrors.push(
        'Address selected for individual is not same as Household address.'
      );
    }

    if (
      individualLowestAddressType === SCHOOL_UUID &&
      householdSecondLowestAddress &&
      individualSecondLowestAddress &&
      individualSecondLowestAddress !== householdSecondLowestAddress
    ) {
      validationErrors.push(
        'Selected village for individual is not same as Household village.'
      );
    }
  }

  /* ---------------- DISPLAY ---------------- */

  value = individualLowestAddressName;

  return new imports.rulesConfig.FormElementStatus(
    formElement.uuid,
    visibility,
    value,
    answersToSkip,
    validationErrors
  );
