      const weight = encounter.getObservationValue('97eda093-1ec0-446f-bb7d-4557e687989a');

      const {zScore} = imports.common.calculateGrowthStatusForAdolescent({
        individual: encounter.individual, 
        weight: weight, 
        height: height, 
        asOnDate: encounter.encounterDateTime
      })
